import json, glob, re, os

patterns = [
    (re.compile(r'gcloud\s+builds\s+triggers\s+(disable|enable|update|import|delete|create)', re.I), 'gcloud-trigger-mutate'),
    (re.compile(r'triggers?[\s"\']*disabled?', re.I), 'disable-trigger-word'),
    (re.compile(r'--substitutions', re.I), 'cli-substitutions'),
    (re.compile(r'"substitutions"\s*:', re.I), 'json-substitutions'),
]

files = glob.glob('**/*.jsonl', recursive=True)
hits = {}
for f in files:
    try:
        with open(f, encoding='utf-8') as fh:
            for ln, line in enumerate(fh, 1):
                for pat, label in patterns:
                    for m in pat.finditer(line):
                        s = max(0, m.start()-120); e = min(len(line), m.end()+160)
                        snip = line[s:e].replace('\\n',' ')
                        hits.setdefault(f, []).append((ln,label,snip))
    except Exception as ex:
        pass

for f, hs in hits.items():
    print("="*30, f, f"({len(hs)} hits)")
    for ln,label,snip in hs[:8]:
        print(f"  L{ln} [{label}]: ...{snip}...")
